56	// ─── Telemetry helper ─────────────────────────────────────────────────────────
57	
58	/**
59	 * Options for trackAnalysisResult. Callers may supply an onSuccess callback for
60	 * any handler-specific events (e.g., insight_generated) that fire only on success.
61	 */
62	interface TrackAnalysisOptions {
63	  /** Called after the success-path analysis_run event — emit extra events here. */
64	  onSuccess?: () => void;
65	}
66	
67	/**
68	 * Emit the 'analysis_run' telemetry event (and captureError on failure) for a
69	 * completed analysis call. Encapsulates the boilerplate shared across the session,
70	 * prompt-quality, and recurring handlers in analysis.ts.
71	 *
72	 * Usage:
73	 *   trackAnalysisResult('session', result, startTime, {
74	 *     onSuccess: () => trackEvent('insight_generated', { type: 'session', count: result.insights.length }),
75	 *   });
76	 */
77	export function trackAnalysisResult(
78	  analysisType: string,
79	  result: Pick<AnalysisResult, 'success' | 'error' | 'error_type' | 'response_preview'>,
80	  startTime: number,
81	  options?: TrackAnalysisOptions,
82	): void {
83	  const llmConfig = loadLLMConfig();
84	  const baseProperties: Record<string, unknown> = {
85	    type: analysisType,
86	    llm_provider: llmConfig?.provider,
87	    llm_model: llmConfig?.model,
88	    duration_ms: Date.now() - startTime,
89	    success: result.success,
90	  };
91	
92	  if (!result.success) {
93	    const errorProperties: Record<string, unknown> = {
94	      ...baseProperties,
95	      error_type: result.error_type,
96	      error_message: result.error,
97	      response_preview: result.response_preview,
98	    };
99	    trackEvent('analysis_run', errorProperties);
100	    captureError(new Error(result.error ?? `${analysisType} analysis failed`), errorProperties);
